"use client";

import { useState, useRef } from "react";

interface Props {
  prompt: string;
}

export default function PromptOutput({ prompt }: Props) {
  const [copied, setCopied] = useState(false);
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  async function handleCopy() {
    try {
      if (
        navigator.clipboard &&
        typeof navigator.clipboard.writeText === "function"
      ) {
        await navigator.clipboard.writeText(prompt);
        showCopied();
      } else {
        // Fallback: select text and prompt keyboard copy
        fallbackCopy();
      }
    } catch {
      fallbackCopy();
    }
  }

  function fallbackCopy() {
    if (textAreaRef.current) {
      textAreaRef.current.select();
      textAreaRef.current.setSelectionRange(
        0,
        textAreaRef.current.value.length,
      );
      // Show keyboard instructions
      setCopied(false);
      // Focus the textarea so user can press Ctrl+C / Cmd+C
      textAreaRef.current.focus();
    }
  }

  function showCopied() {
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  return (
    <section
      aria-label="Customized ballot research prompt"
      className="bg-white border border-gray-200 rounded-xl p-6 shadow-sm"
    >
      <h2 className="text-xl font-bold text-gray-900 mb-2">
        Your Customized Prompt
      </h2>
      <p className="text-gray-600 text-sm mb-4">
        Copy this prompt and paste it as your first message in any AI chatbot
        (Claude, ChatGPT, Gemini, or Grok).
      </p>

      <div className="relative">
        <textarea
          ref={textAreaRef}
          data-testid="prompt-output"
          readOnly
          value={prompt}
          aria-label="Customized ballot research prompt text"
          aria-multiline="true"
          className="w-full h-64 sm:h-80 p-4 text-sm font-mono bg-gray-50 border border-gray-300 rounded-lg resize-none focus:outline-none focus:ring-2 focus:ring-blue-600 overflow-y-auto"
        />
      </div>

      <div className="mt-4 flex items-center gap-3">
        <button
          data-testid="copy-button"
          onClick={handleCopy}
          aria-label="Copy prompt to clipboard"
          className="flex items-center gap-2 bg-blue-700 text-white rounded-lg px-5 py-3 text-base font-semibold min-h-[44px] hover:bg-blue-800 focus:outline-none focus:ring-2 focus:ring-blue-600 focus:ring-offset-2 transition-colors"
        >
          {copied ? (
            <>
              <svg
                aria-hidden="true"
                className="w-5 h-5"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M5 13l4 4L19 7"
                />
              </svg>
              Copied!
            </>
          ) : (
            <>
              <svg
                aria-hidden="true"
                className="w-5 h-5"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3"
                />
              </svg>
              Copy to Clipboard
            </>
          )}
        </button>

        {copied && (
          <span
            data-testid="copy-confirmation"
            role="status"
            aria-live="polite"
            className="text-green-700 font-medium text-sm"
          >
            Copied to clipboard!
          </span>
        )}
      </div>
    </section>
  );
}

"use client";

import type { StateData, Election, DeadlineStatus } from "@/types";
import {
  getDeadlineStatus,
  formatDate,
  allDeadlinesPassed,
} from "@/lib/deadlineUtils";

interface Props {
  stateData: StateData;
  nextElection: Election | null;
}

const tierStyles: Record<DeadlineStatus["tier"], string> = {
  green: "text-green-700 bg-green-50 border-green-200",
  yellow: "text-amber-800 bg-amber-50 border-amber-200",
  red: "text-red-800 bg-red-50 border-red-200",
  passed: "text-gray-600 bg-gray-50 border-gray-200",
};

function DeadlineBadge({
  deadline,
  label,
}: {
  deadline: string | null;
  label: string;
}) {
  if (!deadline)
    return <span className="text-gray-500 text-sm">Not available</span>;
  const status = getDeadlineStatus(deadline);
  return (
    <span
      className={`inline-flex items-center gap-1 px-2 py-0.5 rounded border text-xs font-medium ${tierStyles[status.tier]}`}
    >
      <span>{label}:</span>
      <span>{formatDate(deadline)}</span>
      <span aria-label={`Status: ${status.label}`}>({status.label})</span>
    </span>
  );
}

// eslint-disable-next-line complexity
export default function StateInfoCard({ stateData, nextElection }: Props) {
  const { stateName, registration, earlyVoting, votingRules, resources } =
    stateData;

  const deadlinesPassed = nextElection
    ? allDeadlinesPassed(registration)
    : false;

  return (
    <article
      data-testid="state-info"
      aria-label={`Election information for ${stateName}`}
      className="bg-white border border-gray-200 rounded-xl p-6 shadow-sm"
    >
      <h2 className="text-2xl font-bold text-gray-900 mb-4">
        {stateName} Election Info
      </h2>

      {/* No upcoming election */}
      {!nextElection && (
        <div
          data-testid="no-election-message"
          role="alert"
          className="p-4 bg-yellow-50 border border-yellow-200 rounded-lg text-yellow-800 mb-4"
        >
          <p className="font-semibold">
            No upcoming elections found for {stateName}.
          </p>
          <p className="text-sm mt-1">
            Check{" "}
            <a
              href={resources.stateElectionWebsite}
              target="_blank"
              rel="noopener noreferrer"
              className="underline hover:text-yellow-700"
            >
              {stateName}&apos;s election website
            </a>{" "}
            for updates.
          </p>
        </div>
      )}

      {/* Election details */}
      {nextElection && (
        <div className="space-y-4">
          <div className="flex flex-col gap-1">
            <span className="text-sm font-medium text-gray-500 uppercase tracking-wide">
              Upcoming Election
            </span>
            <span
              data-testid="election-name"
              className="text-lg font-semibold text-gray-800"
            >
              {nextElection.name}
            </span>
            <span data-testid="election-date" className="text-gray-600">
              {formatDate(nextElection.date)}
            </span>
          </div>

          {/* All deadlines passed alert */}
          {deadlinesPassed && (
            <div
              role="alert"
              className="p-3 bg-red-50 border border-red-200 rounded-lg text-red-800 text-sm"
            >
              <strong>
                Registration deadlines for this election have passed.
              </strong>{" "}
              <a
                href={registration.registrationCheckUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="underline hover:text-red-700"
              >
                Check your registration status
              </a>
              .
            </div>
          )}

          {/* Registration deadlines */}
          <div>
            <h3 className="text-base font-semibold text-gray-700 mb-2">
              Voter Registration
            </h3>
            <div
              data-testid="registration-status"
              className="flex flex-col gap-2"
            >
              <div className="flex items-center gap-2 flex-wrap">
                <span className="text-sm text-gray-600 w-16 shrink-0">
                  Online:
                </span>
                <DeadlineBadge
                  deadline={
                    registration.online.available
                      ? registration.online.deadline
                      : null
                  }
                  label="Online"
                />
              </div>
              <div className="flex items-center gap-2 flex-wrap">
                <span className="text-sm text-gray-600 w-16 shrink-0">
                  By mail:
                </span>
                <DeadlineBadge
                  deadline={registration.byMail.deadline}
                  label="Mail"
                />
                {registration.byMail.sincePostmarked && (
                  <span className="text-xs text-gray-500">(by postmark)</span>
                )}
              </div>
              <div className="flex items-center gap-2 flex-wrap">
                <span className="text-sm text-gray-600 w-16 shrink-0">
                  In person:
                </span>
                <DeadlineBadge
                  deadline={registration.inPerson.deadline}
                  label="In person"
                />
              </div>
              {registration.sameDayRegistration && (
                <p className="text-sm text-green-700 font-medium">
                  Same-day registration available
                </p>
              )}
            </div>
          </div>

          {/* Early voting */}
          {earlyVoting.available &&
            earlyVoting.startDate &&
            earlyVoting.endDate && (
              <div>
                <h3 className="text-base font-semibold text-gray-700 mb-1">
                  Early Voting
                </h3>
                <p className="text-sm text-gray-600">
                  {formatDate(earlyVoting.startDate)} –{" "}
                  {formatDate(earlyVoting.endDate)}
                  {earlyVoting.notes && (
                    <span className="text-gray-500">
                      {" "}
                      ({earlyVoting.notes})
                    </span>
                  )}
                </p>
              </div>
            )}

          {/* Voting rules */}
          <div>
            <h3 className="text-base font-semibold text-gray-700 mb-1">
              Voting Rules
            </h3>
            <ul className="text-sm text-gray-600 space-y-1 list-disc list-inside">
              {votingRules.idRequired ? (
                <li>
                  <strong>Photo ID required.</strong>{" "}
                  {votingRules.acceptedIds.length > 0 && (
                    <span>{votingRules.acceptedIds[0]}, and others.</span>
                  )}
                </li>
              ) : (
                <li>Photo ID not required.</li>
              )}
              <li>{votingRules.phonesAtPollsDetail}</li>
            </ul>
          </div>

          {/* Resources */}
          <div>
            <h3 className="text-base font-semibold text-gray-700 mb-1">
              Resources
            </h3>
            <ul className="text-sm space-y-1">
              <li>
                <a
                  href={resources.sampleBallotLookup}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-700 hover:underline"
                >
                  Sample ballot lookup
                </a>
              </li>
              <li>
                <a
                  href={resources.countyElectionLookup}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-700 hover:underline"
                >
                  County election office
                </a>
              </li>
              <li>
                <a
                  href={resources.stateElectionWebsite}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-700 hover:underline"
                >
                  {stateName} election website
                </a>
              </li>
            </ul>
          </div>
        </div>
      )}
    </article>
  );
}

"use client";

import { useState } from "react";
import type { StateData, Election } from "@/types";
import { lookupZip } from "@/lib/zipLookup";
import { getStateData } from "@/lib/stateData";
import { findNextElection } from "@/lib/deadlineUtils";
import { buildCustomizedPrompt } from "@/lib/promptBuilder";
import StateInfoCard from "./StateInfoCard";
import PromptOutput from "./PromptOutput";

type LookupState =
  | { status: "idle" }
  | { status: "loading" }
  | { status: "multistate"; zip: string; states: string[] }
  | { status: "notfound"; zip: string }
  | {
      status: "loaded";
      zip: string;
      stateData: StateData;
      nextElection: Election | null;
      prompt: string;
    }
  | { status: "nostate"; stateCode: string };

// eslint-disable-next-line complexity
export default function ZipLookup() {
  const [zipValue, setZipValue] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [lookupState, setLookupState] = useState<LookupState>({
    status: "idle",
  });

  function validateZip(value: string): string | null {
    if (!value.trim()) return "Please enter a zip code";
    if (!/^\d{5}$/.test(value.trim()))
      return "Please enter a valid 5-digit zip code";
    return null;
  }

  async function handleSubmit(zip: string) {
    const trimmed = zip.trim();
    const validationError = validateZip(trimmed);
    if (validationError) {
      setError(validationError);
      return;
    }
    setError(null);
    setLookupState({ status: "loading" });

    const states = lookupZip(trimmed);
    if (!states) {
      setLookupState({ status: "notfound", zip: trimmed });
      return;
    }
    if (states.length > 1) {
      setLookupState({ status: "multistate", zip: trimmed, states });
      return;
    }
    await loadState(trimmed, states[0]);
  }

  async function loadState(zip: string, stateCode: string) {
    setLookupState({ status: "loading" });
    const stateData = await getStateData(stateCode);
    if (!stateData) {
      setLookupState({ status: "nostate", stateCode });
      return;
    }
    const nextElection = findNextElection(stateData.elections);
    const prompt = nextElection
      ? buildCustomizedPrompt(stateData, zip, nextElection)
      : "";
    setLookupState({ status: "loaded", zip, stateData, nextElection, prompt });
  }

  function handleFormSubmit(e: React.FormEvent) {
    e.preventDefault();
    handleSubmit(zipValue);
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === "Enter") {
      handleSubmit(zipValue);
    }
  }

  return (
    <section
      aria-label="Zip code lookup"
      className="w-full max-w-2xl mx-auto px-4"
    >
      <form
        onSubmit={handleFormSubmit}
        noValidate
        className="flex flex-col gap-3"
      >
        <label
          htmlFor="zip-input"
          className="text-lg font-semibold text-gray-800"
        >
          Enter your zip code
        </label>
        <div className="flex gap-2 flex-col sm:flex-row">
          <input
            id="zip-input"
            data-testid="zip-input"
            type="text"
            inputMode="numeric"
            pattern="[0-9]*"
            maxLength={5}
            placeholder="e.g., 73301"
            value={zipValue}
            onChange={(e) => {
              setZipValue(e.target.value);
              if (error) setError(null);
            }}
            onKeyDown={handleKeyDown}
            aria-label="5-digit zip code"
            aria-describedby={error ? "zip-error" : undefined}
            aria-invalid={error ? "true" : undefined}
            className="flex-1 border border-gray-300 rounded-lg px-4 py-3 text-base min-h-[44px] focus:outline-none focus:ring-2 focus:ring-blue-600 focus:border-transparent"
          />
          <button
            type="submit"
            data-testid="zip-submit"
            className="bg-blue-700 text-white rounded-lg px-6 py-3 text-base font-semibold min-h-[44px] min-w-[120px] hover:bg-blue-800 focus:outline-none focus:ring-2 focus:ring-blue-600 focus:ring-offset-2 transition-colors"
          >
            Look up
          </button>
        </div>

        {error && (
          <p
            id="zip-error"
            data-testid="zip-error"
            role="alert"
            className="text-red-700 text-sm font-medium"
          >
            {error}
          </p>
        )}
      </form>

      {/* Loading state */}
      {lookupState.status === "loading" && (
        <div
          role="status"
          aria-live="polite"
          className="mt-6 text-center text-gray-600"
        >
          <span className="inline-block animate-pulse">
            Looking up your zip code…
          </span>
        </div>
      )}

      {/* Not found */}
      {lookupState.status === "notfound" && (
        <div
          data-testid="not-found-message"
          role="alert"
          className="mt-6 p-4 bg-yellow-50 border border-yellow-200 rounded-lg text-yellow-800"
        >
          <p className="font-semibold">Zip code not found</p>
          <p className="mt-1 text-sm">
            We don&apos;t have data for zip code {lookupState.zip} yet.
            We&apos;re working on adding all U.S. zip codes.{" "}
            <a
              href="https://www.usa.gov/election-office"
              target="_blank"
              rel="noopener noreferrer"
              className="underline text-yellow-900 hover:text-yellow-700"
            >
              Find your state election website
            </a>
            .
          </p>
        </div>
      )}

      {/* Multi-state selector */}
      {lookupState.status === "multistate" && (
        <div className="mt-6 p-4 bg-blue-50 border border-blue-200 rounded-lg">
          <p className="font-semibold text-blue-900 mb-3">
            This zip code spans multiple states. Which state are you voting in?
          </p>
          <div
            data-testid="state-selector"
            className="flex flex-col sm:flex-row gap-2"
          >
            {lookupState.states.map((stateCode) => (
              <button
                key={stateCode}
                onClick={() => loadState(lookupState.zip, stateCode)}
                className="flex-1 bg-white border border-blue-300 text-blue-800 rounded-lg px-4 py-3 text-base font-medium min-h-[44px] hover:bg-blue-100 focus:outline-none focus:ring-2 focus:ring-blue-600 transition-colors"
              >
                {stateCode}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* No state data */}
      {lookupState.status === "nostate" && (
        <div
          data-testid="not-found-message"
          role="alert"
          className="mt-6 p-4 bg-yellow-50 border border-yellow-200 rounded-lg text-yellow-800"
        >
          <p className="font-semibold">State data not available</p>
          <p className="mt-1 text-sm">
            We don&apos;t have data for {lookupState.stateCode} yet. We&apos;re
            working on expanding coverage.{" "}
            <a
              href="https://www.usa.gov/election-office"
              target="_blank"
              rel="noopener noreferrer"
              className="underline text-yellow-900 hover:text-yellow-700"
            >
              Find your state election website
            </a>
            .
          </p>
        </div>
      )}

      {/* Loaded: show state info card and prompt */}
      {lookupState.status === "loaded" && (
        <div className="mt-6 flex flex-col gap-6">
          <StateInfoCard
            stateData={lookupState.stateData}
            nextElection={lookupState.nextElection}
          />
          {lookupState.nextElection && lookupState.prompt && (
            <PromptOutput prompt={lookupState.prompt} />
          )}
        </div>
      )}
    </section>
  );
}

import type { DeadlineStatus, DeadlineStatusTier } from "@/types";

/**
 * Calculate deadline status relative to today.
 * @param isoDate - ISO date string "YYYY-MM-DD"
 * @returns DeadlineStatus with tier, daysRemaining, label, and date
 */
export function getDeadlineStatus(isoDate: string): DeadlineStatus {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const deadline = new Date(isoDate + "T00:00:00");
  deadline.setHours(0, 0, 0, 0);

  const diffMs = deadline.getTime() - today.getTime();
  const diffDays = Math.ceil(diffMs / (1000 * 60 * 60 * 24));

  let tier: DeadlineStatusTier;
  let daysRemaining: number | null;
  let label: string;

  if (diffDays < 0) {
    tier = "passed";
    daysRemaining = null;
    label = "Passed";
  } else if (diffDays === 0) {
    tier = "red";
    daysRemaining = 0;
    label = "Today — last day!";
  } else if (diffDays <= 3) {
    tier = "red";
    daysRemaining = diffDays;
    label = `${diffDays} day${diffDays === 1 ? "" : "s"} left`;
  } else if (diffDays <= 14) {
    tier = "yellow";
    daysRemaining = diffDays;
    label = `${diffDays} days left`;
  } else {
    tier = "green";
    daysRemaining = diffDays;
    label = `${diffDays} days left`;
  }

  return { tier, daysRemaining, label, date: isoDate };
}

/**
 * Format an ISO date string to a human-readable date.
 * e.g., "2026-03-03" → "March 3, 2026"
 */
export function formatDate(isoDate: string): string {
  const date = new Date(isoDate + "T00:00:00");
  return date.toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

/**
 * Find the next upcoming election (first election with date >= today).
 */
export function findNextElection<T extends { date: string }>(
  elections: T[],
): T | null {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const found = elections.find((e) => {
    const electionDate = new Date(e.date + "T00:00:00");
    electionDate.setHours(0, 0, 0, 0);
    return electionDate >= today;
  });
  return found ?? null;
}

/**
 * Check if all registration deadlines have passed.
 */
export function allDeadlinesPassed(registration: {
  online: { deadline: string | null };
  byMail: { deadline: string };
  inPerson: { deadline: string };
}): boolean {
  const deadlines = [
    registration.online.deadline,
    registration.byMail.deadline,
    registration.inPerson.deadline,
  ].filter(Boolean) as string[];

  return deadlines.every((d) => getDeadlineStatus(d).tier === "passed");
}

import type { StateData } from "@/types";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type JsonImport = () => Promise<{ default: any }>;

const stateModules: Record<string, JsonImport> = {
  TX: () => import("@/data/states/TX.json"),
  CA: () => import("@/data/states/CA.json"),
  NH: () => import("@/data/states/NH.json"),
};

/**
 * Load state election data for a given state code.
 * @returns StateData or null if state not found in dataset.
 */
export async function getStateData(
  stateCode: string,
): Promise<StateData | null> {
  const loader = stateModules[stateCode.toUpperCase()];
  if (!loader) return null;
  try {
    const mod = await loader();
    return mod.default as StateData;
  } catch {
    return null;
  }
}

import type { ZipToStateMap } from "@/types";
import zipData from "@/data/zip-to-state.json";

const zipToStateMap: ZipToStateMap = zipData as ZipToStateMap;

/**
 * Look up state code(s) for a given 5-digit zip code.
 * @returns Array of 2-letter state codes, or null if not found.
 */
export function lookupZip(zip: string): string[] | null {
  const states = zipToStateMap[zip];
  if (!states || states.length === 0) return null;
  return states;
}
